def is_prime(n):
    """
    Check if a number is prime.

    Args:
        n: An integer to check for primality

    Returns:
        True if n is prime, False otherwise
    """
    # Handle edge cases
    if n <= 1:
        return False
    if n <= 3:
        return True  # 2 and 3 are prime

    # Check if n is divisible by 2 or 3
    if n % 2 == 0 or n % 3 == 0:
        return False

    # Check for divisors from 5 to sqrt(n)
    # We only need to check up to sqrt(n) because if n has a divisor
    # greater than sqrt(n), it must have a corresponding divisor less than sqrt(n)
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6

    return True


