import math

def is_prime(n: int) -> bool:
    """
    Return True if `n` is a prime number, otherwise False.
    """
    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False

    limit = int(math.isqrt(n)) + 1
    for d in range(3, limit, 2):
        if n % d == 0:
            return False
    return True


